if n <= 1:
        return 0  # no proper divisor exists
    # Search for the smallest divisor (>1). Its complement will be the largest proper divisor.
    limit = int(n ** 0.5) + 1
    for i in range(2, limit):
        if n % i == 0:
            return n // i
    # If no divisor found, n is prime, so the largest proper divisor is 1
    return 1
